+        var buf: std.ArrayList(u8) = .{};
+        defer buf.deinit(self.allocator);
+        try type_.emit(buf.writer(self.allocator));
+        return try self.allocator.dupe(u8, buf.items);
+    }
+};
+
+/// Statistics about local allocation
