+                    try self.emitValueCore(field.value);
+                }
+                try self.write(" }");
+            },
+            .method_result => |m| {
+                try self.emitValueCore(m.receiver.*);
+                try self.writeFmt(".{s}(", .{m.method});
+                for (m.args, 0..) |arg, i| {
+                    if (i > 0) try self.write(", ");
+                    try self.emitValueCore(arg);
+                }
+                try self.write(")");
+            },
+            .binop_result => |b| {
+                try self.emitValueCore(b.lhs.*);
+                try self.write(" ");
+                try self.write(binOpStr(b.op));
