+    const PrimitiveTypes = struct {
+        void_t: ZigType = .void,
+        bool_t: ZigType = .bool,
+        i8_t: ZigType = .i8,
+        i16_t: ZigType = .i16,
+        i32_t: ZigType = .i32,
+        i64_t: ZigType = .i64,
+        i128_t: ZigType = .i128,
+        u8_t: ZigType = .u8,
+        u16_t: ZigType = .u16,
+        u32_t: ZigType = .u32,
+        u64_t: ZigType = .u64,
+        usize_t: ZigType = .usize,
+        f32_t: ZigType = .f32,
+        f64_t: ZigType = .f64,
+        pyvalue_t: ZigType = .pyvalue,
+        bigint_t: ZigType = .bigint,
+        unified_int_t: ZigType = .unified_int,
