+        // Boolean: +True -> 1, +False -> 0
+        const operand = try self.captureExpr(unaryop.operand.*);
+        try self.emit("@as(i64, @intFromBool(");
+        try self.emitZigValue(operand);
+        try self.emit("))");
+    } else {
