-/// Comparison magic methods that return bool
-const ComparisonMagicMethods = std.StaticStringMap(void).initComptime(.{
-    .{ "__eq__", {} },
-    .{ "__ne__", {} },
-    .{ "__lt__", {} },
-    .{ "__le__", {} },
-    .{ "__gt__", {} },
-    .{ "__ge__", {} },
